-- Auto-generated by pg_pack (purchase, purchase_ut)
-- 2026-03-12

-- Schema: purchase
CREATE SCHEMA IF NOT EXISTS purchase;

CREATE OR REPLACE FUNCTION purchase._article_options()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text := '<option value="">— aucun —</option>';
  v_opts text;
  v_sql text;
  r record;
BEGIN
  -- Priority: catalog > stock > empty
  SELECT 'SELECT ' || n.nspname || '.article_options()'
    INTO v_sql
    FROM pg_namespace n
    JOIN pg_proc p ON p.pronamespace = n.oid AND p.proname = 'article_options'
   WHERE n.nspname = 'catalog';
  IF v_sql IS NOT NULL THEN
    EXECUTE v_sql INTO v_opts;
    RETURN v_html || coalesce(v_opts, '');
  END IF;

  IF EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'stock') THEN
    FOR r IN EXECUTE 'SELECT id, reference, designation FROM stock.article WHERE active = true ORDER BY reference'
    LOOP
      v_html := v_html || format('<option value="%s">%s — %s</option>', r.id, pgv.esc(r.reference), pgv.esc(r.designation));
    END LOOP;
  END IF;

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION purchase._article_options() IS 'Generate HTML option list from stock.article (dynamic, no hard dep on stock schema)';

CREATE OR REPLACE FUNCTION purchase._fournisseur_options()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text := '<option value="">-- Choisir un fournisseur --</option>';
  r record;
BEGIN
  FOR r IN SELECT id, name FROM crm.client WHERE active ORDER BY name LOOP
    v_html := v_html || format('<option value="%s">%s</option>', r.id, pgv.esc(r.name));
  END LOOP;
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION purchase._fournisseur_options() IS 'HTML select options for CRM clients as suppliers';

CREATE OR REPLACE FUNCTION purchase._next_numero(p_prefix text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year text := to_char(now(), 'YYYY');
  v_seq int;
BEGIN
  SELECT coalesce(max(
    regexp_replace(numero, '^.*-(\d+)$', '\1')::int
  ), 0) + 1
  INTO v_seq
  FROM purchase.commande
  WHERE numero LIKE p_prefix || '-' || v_year || '-%'
  UNION ALL
  SELECT coalesce(max(
    regexp_replace(numero, '^.*-(\d+)$', '\1')::int
  ), 0) + 1
  FROM purchase.reception
  WHERE numero LIKE p_prefix || '-' || v_year || '-%'
  ORDER BY 1 DESC LIMIT 1;

  RETURN p_prefix || '-' || v_year || '-' || lpad(v_seq::text, 3, '0');
END;
$function$;
COMMENT ON FUNCTION purchase._next_numero(text) IS 'Generate next sequential number (CMD-2026-001, REC-2026-001)';

CREATE OR REPLACE FUNCTION purchase._quantite_restante(p_ligne_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_commandee numeric;
  v_recue numeric;
BEGIN
  SELECT quantite INTO v_commandee FROM purchase.ligne WHERE id = p_ligne_id;
  SELECT coalesce(sum(quantite_recue), 0) INTO v_recue
    FROM purchase.reception_ligne WHERE ligne_id = p_ligne_id;
  RETURN v_commandee - v_recue;
END;
$function$;
COMMENT ON FUNCTION purchase._quantite_restante(integer) IS 'Remaining quantity to receive for an order line';

CREATE OR REPLACE FUNCTION purchase._set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := now();
  RETURN NEW;
END;
$function$;
COMMENT ON FUNCTION purchase._set_updated_at() IS 'Trigger function to auto-update updated_at timestamp';

CREATE OR REPLACE FUNCTION purchase._statut_badge(p_statut text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN CASE p_statut
    WHEN 'brouillon' THEN pgv.badge(p_statut, 'default')
    WHEN 'envoyee' THEN pgv.badge(p_statut, 'primary')
    WHEN 'partiellement_recue' THEN pgv.badge('partielle', 'warning')
    WHEN 'recue' THEN pgv.badge(p_statut, 'success')
    WHEN 'annulee' THEN pgv.badge(p_statut, 'danger')
    WHEN 'validee' THEN pgv.badge(p_statut, 'success')
    WHEN 'payee' THEN pgv.badge(p_statut, 'success')
    ELSE pgv.badge(p_statut, 'default')
  END;
END;
$function$;
COMMENT ON FUNCTION purchase._statut_badge(text) IS 'Colored status badge for purchase statuses';

CREATE OR REPLACE FUNCTION purchase._total_ht(p_commande_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN coalesce((
    SELECT sum(quantite * prix_unitaire)
    FROM purchase.ligne
    WHERE commande_id = p_commande_id
  ), 0);
END;
$function$;
COMMENT ON FUNCTION purchase._total_ht(integer) IS 'Total HT for a purchase order';

CREATE OR REPLACE FUNCTION purchase._total_tva(p_commande_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN coalesce((
    SELECT sum(quantite * prix_unitaire * tva_rate / 100)
    FROM purchase.ligne
    WHERE commande_id = p_commande_id
  ), 0);
END;
$function$;
COMMENT ON FUNCTION purchase._total_tva(integer) IS 'Total TVA for a purchase order';

CREATE OR REPLACE FUNCTION purchase._total_ttc(p_commande_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN purchase._total_ht(p_commande_id) + purchase._total_tva(p_commande_id);
END;
$function$;
COMMENT ON FUNCTION purchase._total_ttc(integer) IS 'Total TTC for a purchase order';

CREATE OR REPLACE FUNCTION purchase.brand()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN 'Achats';
END;
$function$;
COMMENT ON FUNCTION purchase.brand() IS 'Brand name for purchase module';

CREATE OR REPLACE FUNCTION purchase.get_article_prix(p_article_id integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_ref text;
  v_designation text;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  -- Retrieve article info (priority: catalog > stock)
  IF EXISTS (SELECT 1 FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
             WHERE n.nspname = 'catalog' AND c.relname = 'article') THEN
    EXECUTE format('SELECT reference, designation FROM catalog.article WHERE id = %L', p_article_id)
      INTO v_ref, v_designation;
  ELSIF EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'stock') THEN
    EXECUTE format('SELECT reference, designation FROM stock.article WHERE id = %L', p_article_id)
      INTO v_ref, v_designation;
  END IF;

  IF v_ref IS NULL THEN
    v_ref := '#' || p_article_id;
    v_designation := 'Article ' || p_article_id;
  END IF;

  v_body := '<h3>Historique prix — ' || pgv.esc(v_ref) || ' ' || pgv.esc(v_designation) || '</h3>';

  -- Price history: all purchase lines with this article_id, grouped by supplier
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT cl.name AS fournisseur, c.numero, l.prix_unitaire, l.unite,
           l.quantite, c.created_at,
           purchase._statut_badge(c.statut) AS badge
      FROM purchase.ligne l
      JOIN purchase.commande c ON c.id = l.commande_id
      JOIN crm.client cl ON cl.id = c.fournisseur_id
     WHERE l.article_id = p_article_id
     ORDER BY c.created_at DESC
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.fournisseur),
      pgv.esc(r.numero),
      to_char(r.prix_unitaire, 'FM999 990.00') || ' EUR/' || r.unite,
      r.quantite::text || ' ' || r.unite,
      r.badge,
      to_char(r.created_at, 'DD/MM/YYYY')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun achat enregistré pour cet article');
  ELSE
    -- Stats summary
    v_body := v_body || pgv.grid(VARIADIC ARRAY[
      pgv.stat('Achats', (array_length(v_rows, 1) / 6)::text),
      pgv.stat('Prix min', (SELECT to_char(min(l.prix_unitaire), 'FM999 990.00') || ' EUR'
        FROM purchase.ligne l WHERE l.article_id = p_article_id)),
      pgv.stat('Prix max', (SELECT to_char(max(l.prix_unitaire), 'FM999 990.00') || ' EUR'
        FROM purchase.ligne l WHERE l.article_id = p_article_id)),
      pgv.stat('Prix moyen', (SELECT to_char(avg(l.prix_unitaire), 'FM999 990.00') || ' EUR'
        FROM purchase.ligne l WHERE l.article_id = p_article_id))
    ]);
    v_body := v_body || pgv.md_table(
      ARRAY['Fournisseur', 'Commande', 'Prix unitaire', 'Quantité', 'Statut', 'Date'],
      v_rows);
  END IF;

  -- Link to catalog if available
  IF EXISTS (SELECT 1 FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
             WHERE n.nspname = 'catalog' AND c.relname = 'article') THEN
    v_body := v_body || format('<p><a href="/catalog/article?p_id=%s">Voir fiche article</a> | ', p_article_id);
  ELSE
    v_body := v_body || '<p>';
  END IF;
  v_body := v_body || format('<a href="%s">Retour commandes</a></p>', pgv.call_ref('get_commande'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_article_prix(integer) IS 'Historique des prix d achat d un article par fournisseur';

CREATE OR REPLACE FUNCTION purchase.get_bon_commande(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd purchase.commande;
  v_fournisseur record;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  SELECT * INTO v_cmd FROM purchase.commande WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty('Commande introuvable'); END IF;

  -- Fournisseur details
  SELECT cl.name, cl.email, cl.phone, cl.address, cl.city
    INTO v_fournisseur
    FROM crm.client cl WHERE cl.id = v_cmd.fournisseur_id;

  -- Header
  v_body := '<div class="pgv-print">';
  v_body := v_body || '<h2>Bon de commande ' || pgv.esc(v_cmd.numero) || '</h2>';

  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.card('Fournisseur',
      pgv.esc(v_fournisseur.name)
      || coalesce('<br>' || pgv.esc(v_fournisseur.address), '')
      || coalesce('<br>' || pgv.esc(v_fournisseur.city), '')
      || coalesce('<br>' || pgv.esc(v_fournisseur.email), '')
      || coalesce('<br>' || pgv.esc(v_fournisseur.phone), '')
    ),
    pgv.card('Commande',
      '<strong>N° :</strong> ' || pgv.esc(v_cmd.numero)
      || '<br><strong>Date :</strong> ' || to_char(v_cmd.created_at, 'DD/MM/YYYY')
      || '<br><strong>Objet :</strong> ' || pgv.esc(v_cmd.objet)
      || CASE WHEN v_cmd.date_livraison IS NOT NULL
         THEN '<br><strong>Livraison souhaitée :</strong> ' || to_char(v_cmd.date_livraison, 'DD/MM/YYYY')
         ELSE '' END
      || CASE WHEN v_cmd.conditions_paiement <> ''
         THEN '<br><strong>Paiement :</strong> ' || pgv.esc(v_cmd.conditions_paiement)
         ELSE '' END
    )
  ]);

  -- Lines table
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT l.description, l.quantite, l.unite, l.prix_unitaire, l.tva_rate,
           round(l.quantite * l.prix_unitaire, 2) AS total_ht
      FROM purchase.ligne l
     WHERE l.commande_id = p_id
     ORDER BY l.sort_order
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.description),
      r.quantite::text,
      r.unite,
      to_char(r.prix_unitaire, 'FM999 990.00'),
      r.tva_rate::text || '%',
      to_char(r.total_ht, 'FM999 990.00')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || pgv.md_table(
      ARRAY['Désignation', 'Qté', 'Unité', 'PU HT', 'TVA', 'Total HT'],
      v_rows);
  END IF;

  -- Totals
  v_body := v_body || '<p>'
    || '<strong>Total HT :</strong> ' || to_char(purchase._total_ht(p_id), 'FM999 990.00') || ' EUR'
    || ' | <strong>TVA :</strong> ' || to_char(purchase._total_tva(p_id), 'FM999 990.00') || ' EUR'
    || ' | <strong>Total TTC :</strong> ' || to_char(purchase._total_ttc(p_id), 'FM999 990.00') || ' EUR'
    || '</p>';

  IF v_cmd.notes <> '' THEN
    v_body := v_body || '<p><strong>Notes :</strong> ' || pgv.esc(v_cmd.notes) || '</p>';
  END IF;

  v_body := v_body || '</div>';

  -- Back link (hidden in print)
  v_body := v_body || format('<p><a href="%s">Retour à la commande</a></p>',
    pgv.call_ref('get_commande', jsonb_build_object('p_id', p_id)));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_bon_commande(integer) IS 'Vue imprimable/PDF-ready d un bon de commande fournisseur';

CREATE OR REPLACE FUNCTION purchase.get_commande(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd purchase.commande;
  v_fournisseur text;
  v_body text;
  v_rows text[];
  v_rows_r text[];
  r record;
BEGIN
  -- Liste si pas d'id
  IF p_id IS NULL THEN
    v_rows := ARRAY[]::text[];
    FOR r IN
      SELECT c.id, c.fournisseur_id, c.numero, cl.name AS fournisseur, c.objet, c.statut,
             purchase._total_ttc(c.id) AS ttc, c.created_at
        FROM purchase.commande c
        JOIN crm.client cl ON cl.id = c.fournisseur_id
       ORDER BY c.created_at DESC
    LOOP
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_commande', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
        format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur)),
        pgv.esc(r.objet),
        purchase._statut_badge(r.statut)
          || CASE WHEN r.statut IN ('envoyee', 'partiellement_recue')
                      AND r.created_at < now() - interval '14 days'
             THEN ' ' || pgv.badge('retard', 'danger')
             ELSE '' END,
        to_char(r.ttc, 'FM999 990.00') || ' EUR',
        to_char(r.created_at, 'DD/MM/YYYY')
      ];
    END LOOP;

    IF array_length(v_rows, 1) IS NULL THEN
      RETURN pgv.empty('Aucune commande', 'Créez votre première commande fournisseur.')
        || format('<p><a href="%s" role="button">Nouvelle commande</a></p>', pgv.call_ref('get_commande_form'));
    END IF;

    RETURN '<p>' || format('<a href="%s" role="button">Nouvelle commande</a>', pgv.call_ref('get_commande_form')) || '</p>'
      || pgv.md_table(ARRAY['Numéro', 'Fournisseur', 'Objet', 'Statut', 'Total TTC', 'Date'], v_rows);
  END IF;

  -- Détail
  SELECT * INTO v_cmd FROM purchase.commande WHERE id = p_id;
  SELECT name INTO v_fournisseur FROM crm.client WHERE id = v_cmd.fournisseur_id;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.card('Commande', v_cmd.numero || '<br>' || purchase._statut_badge(v_cmd.statut)),
    pgv.card('Fournisseur', format('<a href="/crm/client?p_id=%s">%s</a>', v_cmd.fournisseur_id, pgv.esc(v_fournisseur))),
    pgv.card('Total TTC', to_char(purchase._total_ttc(p_id), 'FM999 990.00') || ' EUR'),
    pgv.card('Livraison', coalesce(to_char(v_cmd.date_livraison, 'DD/MM/YYYY'), '—'))
  ]);

  IF v_cmd.objet <> '' THEN
    v_body := v_body || '<p><strong>Objet :</strong> ' || pgv.esc(v_cmd.objet) || '</p>';
  END IF;
  IF v_cmd.conditions_paiement <> '' THEN
    v_body := v_body || '<p><strong>Conditions paiement :</strong> ' || pgv.esc(v_cmd.conditions_paiement) || '</p>';
  END IF;
  IF v_cmd.notes <> '' THEN
    v_body := v_body || '<p><strong>Notes :</strong> ' || pgv.esc(v_cmd.notes) || '</p>';
  END IF;

  -- Lignes
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT l.id, l.description, l.quantite, l.unite, l.prix_unitaire, l.tva_rate,
           (l.quantite * l.prix_unitaire) AS total_ht,
           purchase._quantite_restante(l.id) AS restante,
           l.article_id
      FROM purchase.ligne l
     WHERE l.commande_id = p_id
     ORDER BY l.sort_order
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.description) || CASE WHEN r.article_id IS NOT NULL
        THEN ' ' || format('<a href="%s">', pgv.call_ref('get_article_prix', jsonb_build_object('p_article_id', r.article_id)))
          || pgv.badge('art. #' || r.article_id, 'info') || '</a>'
        ELSE '' END,
      r.quantite::text || ' ' || r.unite,
      to_char(r.prix_unitaire, 'FM999 990.00') || ' EUR',
      r.tva_rate::text || '%',
      to_char(r.total_ht, 'FM999 990.00') || ' EUR',
      CASE WHEN v_cmd.statut IN ('envoyee', 'partiellement_recue')
        THEN r.restante::text || ' ' || r.unite
        ELSE '—'
      END,
      CASE WHEN v_cmd.statut = 'brouillon'
        THEN pgv.action('post_ligne_supprimer', 'Supprimer',
               jsonb_build_object('p_ligne_id', r.id),
               'Supprimer cette ligne ?', 'danger')
        ELSE ''
      END
    ];
  END LOOP;

  v_body := v_body || '<h4>Lignes</h4>';
  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucune ligne');
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Description', 'Qté', 'PU', 'TVA', 'Total HT', 'Restant', ''],
      v_rows);
    v_body := v_body || '<p><strong>Total HT :</strong> ' || to_char(purchase._total_ht(p_id), 'FM999 990.00') || ' EUR'
      || ' | <strong>TVA :</strong> ' || to_char(purchase._total_tva(p_id), 'FM999 990.00') || ' EUR'
      || ' | <strong>TTC :</strong> ' || to_char(purchase._total_ttc(p_id), 'FM999 990.00') || ' EUR</p>';
  END IF;

  -- Formulaire ajout ligne (brouillon)
  IF v_cmd.statut = 'brouillon' THEN
    v_body := v_body || '<details><summary>Ajouter une ligne</summary>'
      || '<form data-rpc="post_ligne_ajouter">'
      || format('<input type="hidden" name="p_commande_id" value="%s">', p_id)
      || '<label>Description<input type="text" name="p_description" required></label>'
      || '<div class="pgv-grid">'
      || '<label>Quantité<input type="number" name="p_quantite" value="1" step="0.01" min="0.01"></label>'
      || '<label>Unité<select name="p_unite"><option value="u">u</option><option value="h">h</option><option value="m">m</option><option value="m2">m²</option><option value="m3">m³</option><option value="kg">kg</option><option value="forfait">forfait</option></select></label>'
      || '<label>Prix unitaire<input type="number" name="p_prix_unitaire" step="0.01" min="0" required></label>'
      || '<label>TVA %<select name="p_tva_rate"><option value="20.00" selected>20%</option><option value="10.00">10%</option><option value="5.50">5.5%</option><option value="0.00">0%</option></select></label>'
      || '</div>'
      || '<label>Article stock<select name="p_article_id">' || purchase._article_options() || '</select></label>'
      || '<button type="submit">Ajouter</button>'
      || '</form></details>';
  END IF;

  -- Réceptions
  v_rows_r := ARRAY[]::text[];
  FOR r IN
    SELECT rc.id, rc.numero, rc.received_at, rc.notes,
           (SELECT count(*) FROM purchase.reception_ligne rl WHERE rl.reception_id = rc.id) AS nb_lignes
      FROM purchase.reception rc
     WHERE rc.commande_id = p_id
     ORDER BY rc.received_at DESC
  LOOP
    v_rows_r := v_rows_r || ARRAY[
      pgv.esc(r.numero),
      to_char(r.received_at, 'DD/MM/YYYY HH24:MI'),
      r.nb_lignes::text || ' lignes',
      coalesce(pgv.esc(r.notes), '')
    ];
  END LOOP;

  IF array_length(v_rows_r, 1) IS NOT NULL THEN
    v_body := v_body || '<h4>Réceptions</h4>'
      || pgv.md_table(ARRAY['Numéro', 'Date', 'Lignes', 'Notes'], v_rows_r);
  END IF;

  -- Bon de commande link
  v_body := v_body || format('<p><a href="%s">Voir le bon de commande</a></p>',
    pgv.call_ref('get_bon_commande', jsonb_build_object('p_id', p_id)));

  -- Actions
  v_body := v_body || '<p>';
  IF v_cmd.statut = 'brouillon' THEN
    v_body := v_body
      || format('<a href="%s" role="button">Modifier</a> ', pgv.call_ref('get_commande_form', jsonb_build_object('p_id', p_id)))
      || pgv.action('post_commande_envoyer', 'Envoyer',
           jsonb_build_object('p_id', p_id),
           'Marquer cette commande comme envoyée ?') || ' '
      || pgv.action('post_commande_annuler', 'Annuler',
           jsonb_build_object('p_id', p_id),
           'Annuler cette commande ?', 'danger');
  ELSIF v_cmd.statut IN ('envoyee', 'partiellement_recue') THEN
    v_body := v_body
      || pgv.action('post_reception_creer', 'Réceptionner',
           jsonb_build_object('p_commande_id', p_id),
           'Créer une réception pour cette commande ?') || ' '
      || pgv.action('post_commande_annuler', 'Annuler',
           jsonb_build_object('p_id', p_id),
           'Annuler cette commande ?', 'danger');
  END IF;
  v_body := v_body || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_commande(integer) IS 'Purchase order detail with lines, receptions, and actions by status';

CREATE OR REPLACE FUNCTION purchase.get_commande_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd purchase.commande;
  v_title text;
  v_body text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_cmd FROM purchase.commande WHERE id = p_id;
    v_title := 'Modifier commande ' || v_cmd.numero;
  ELSE
    v_title := 'Nouvelle commande';
  END IF;

  v_body := '<h3>' || pgv.esc(v_title) || '</h3>'
    || '<form data-rpc="post_commande_save">';

  IF p_id IS NOT NULL THEN
    v_body := v_body || format('<input type="hidden" name="p_id" value="%s">', p_id);
  END IF;

  v_body := v_body
    || '<label>Fournisseur<select name="p_fournisseur_id" required>'
    || purchase._fournisseur_options()
    || '</select></label>';

  -- Pre-select if editing
  IF p_id IS NOT NULL THEN
    v_body := replace(v_body,
      format('value="%s">', v_cmd.fournisseur_id),
      format('value="%s" selected>', v_cmd.fournisseur_id));
  END IF;

  v_body := v_body
    || format('<label>Objet<input type="text" name="p_objet" value="%s" required></label>',
       coalesce(pgv.esc(v_cmd.objet), ''))
    || format('<label>Date livraison prévue<input type="date" name="p_date_livraison" value="%s"></label>',
       coalesce(v_cmd.date_livraison::text, ''))
    || format('<label>Conditions paiement<input type="text" name="p_conditions_paiement" value="%s" placeholder="ex: 30j fin de mois"></label>',
       coalesce(pgv.esc(v_cmd.conditions_paiement), ''))
    || format('<label>Notes<textarea name="p_notes">%s</textarea></label>',
       coalesce(pgv.esc(v_cmd.notes), ''))
    || '<button type="submit">Enregistrer</button>'
    || '</form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_commande_form(integer) IS 'Form to create or edit a purchase order';

CREATE OR REPLACE FUNCTION purchase.get_facture_fournisseur(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_fac purchase.facture_fournisseur;
  v_cmd_numero text;
  v_fournisseur_id int;
  v_fournisseur_name text;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  -- Liste si pas d'id
  IF p_id IS NULL THEN
    v_rows := ARRAY[]::text[];
    FOR r IN
      SELECT f.id, f.numero_fournisseur, c.numero AS cmd_numero,
             cl.id AS fournisseur_id, cl.name AS fournisseur,
             f.montant_ttc, f.statut, f.date_facture, f.date_echeance
        FROM purchase.facture_fournisseur f
        LEFT JOIN purchase.commande c ON c.id = f.commande_id
        LEFT JOIN crm.client cl ON cl.id = c.fournisseur_id
       ORDER BY f.created_at DESC
    LOOP
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero_fournisseur)),
        coalesce(format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur)), '—'),
        coalesce(r.cmd_numero, '—'),
        purchase._statut_badge(r.statut),
        to_char(r.montant_ttc, 'FM999 990.00') || ' EUR',
        to_char(r.date_facture, 'DD/MM/YYYY'),
        coalesce(to_char(r.date_echeance, 'DD/MM/YYYY'), '—')
      ];
    END LOOP;

    IF array_length(v_rows, 1) IS NULL THEN
      RETURN pgv.empty('Aucune facture fournisseur', 'Les factures apparaissent ici après saisie.');
    END IF;

    v_body := '<details><summary>Saisir une facture fournisseur</summary>'
      || '<form data-rpc="post_facture_saisir">'
      || '<label>N° fournisseur<input type="text" name="p_numero_fournisseur" required placeholder="ex: FAC-2026-042"></label>'
      || '<div class="pgv-grid">'
      || '<label>Montant HT<input type="number" name="p_montant_ht" step="0.01" min="0" required></label>'
      || '<label>Montant TTC<input type="number" name="p_montant_ttc" step="0.01" min="0" required></label>'
      || '</div>'
      || '<div class="pgv-grid">'
      || '<label>Date facture<input type="date" name="p_date_facture" required></label>'
      || '<label>Date échéance<input type="date" name="p_date_echeance"></label>'
      || '</div>'
      || '<label>Commande liée<select name="p_commande_id"><option value="">(aucune)</option>';
    FOR r IN SELECT id, numero FROM purchase.commande ORDER BY created_at DESC LIMIT 20 LOOP
      v_body := v_body || format('<option value="%s">%s</option>', r.id, pgv.esc(r.numero));
    END LOOP;
    RETURN v_body
      || '</select></label>'
      || '<label>Notes<textarea name="p_notes"></textarea></label>'
      || '<button type="submit">Saisir</button>'
      || '</form></details>'
      || pgv.md_table(ARRAY['N° fournisseur', 'Fournisseur', 'Commande', 'Statut', 'Montant TTC', 'Date facture', 'Echéance'], v_rows);
  END IF;

  -- Détail
  SELECT * INTO v_fac FROM purchase.facture_fournisseur WHERE id = p_id;
  SELECT numero INTO v_cmd_numero FROM purchase.commande WHERE id = v_fac.commande_id;

  -- Fournisseur via commande
  SELECT c.fournisseur_id, cl.name INTO v_fournisseur_id, v_fournisseur_name
    FROM purchase.commande c
    JOIN crm.client cl ON cl.id = c.fournisseur_id
   WHERE c.id = v_fac.commande_id;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.card('Facture', pgv.esc(v_fac.numero_fournisseur) || '<br>' || purchase._statut_badge(v_fac.statut)),
    pgv.card('Fournisseur', CASE WHEN v_fournisseur_id IS NOT NULL
      THEN format('<a href="/crm/client?p_id=%s">%s</a>', v_fournisseur_id, pgv.esc(v_fournisseur_name))
      ELSE '—' END),
    pgv.card('Commande', coalesce(v_cmd_numero, '—')),
    pgv.card('Montant HT', to_char(v_fac.montant_ht, 'FM999 990.00') || ' EUR'),
    pgv.card('Montant TTC', to_char(v_fac.montant_ttc, 'FM999 990.00') || ' EUR')
  ]);

  v_body := v_body || '<p>'
    || '<strong>Date facture :</strong> ' || to_char(v_fac.date_facture, 'DD/MM/YYYY')
    || ' | <strong>Echéance :</strong> ' || coalesce(to_char(v_fac.date_echeance, 'DD/MM/YYYY'), '—')
    || '</p>';

  IF v_fac.notes <> '' THEN
    v_body := v_body || '<p><strong>Notes :</strong> ' || pgv.esc(v_fac.notes) || '</p>';
  END IF;

  -- Rapprochement: comparer montants commande vs facture
  IF v_fac.commande_id IS NOT NULL THEN
    DECLARE
      v_cmd_ttc numeric;
      v_ecart numeric;
    BEGIN
      v_cmd_ttc := purchase._total_ttc(v_fac.commande_id);
      v_ecart := v_fac.montant_ttc - v_cmd_ttc;
      v_body := v_body || '<p><strong>Rapprochement :</strong> Commande TTC = '
        || to_char(v_cmd_ttc, 'FM999 990.00') || ' EUR'
        || ' | Ecart = ' || to_char(v_ecart, 'FM999 990.00') || ' EUR';
      IF abs(v_ecart) > 0.01 THEN
        v_body := v_body || ' ' || pgv.badge('écart', 'warning');
      ELSE
        v_body := v_body || ' ' || pgv.badge('OK', 'success');
      END IF;
      v_body := v_body || '</p>';
    END;
  END IF;

  -- Actions
  v_body := v_body || '<p>';
  IF v_fac.statut = 'recue' THEN
    v_body := v_body || pgv.action('post_facture_valider', 'Valider',
      jsonb_build_object('p_id', p_id),
      'Valider cette facture ?');
  ELSIF v_fac.statut = 'validee' THEN
    v_body := v_body || pgv.action('post_facture_payer', 'Marquer payée',
      jsonb_build_object('p_id', p_id),
      'Marquer cette facture comme payée ?');
  ELSIF v_fac.statut = 'payee' AND NOT v_fac.comptabilisee THEN
    v_body := v_body || pgv.action('post_facture_comptabiliser', 'Comptabiliser',
      jsonb_build_object('p_id', p_id),
      'Créer l''écriture comptable pour cette facture ?');
  END IF;
  IF v_fac.comptabilisee THEN
    v_body := v_body || ' ' || pgv.badge('comptabilisée', 'success');
  END IF;
  v_body := v_body || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_facture_fournisseur(integer) IS 'Supplier invoice list or detail with reconciliation and CRM links';

CREATE OR REPLACE FUNCTION purchase.get_index()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd_en_cours int;
  v_receptions_attente int;
  v_factures_impayees int;
  v_achats_mois numeric(12,2);
  v_total_a_payer numeric(12,2);
  v_body text;
  v_rows_c text[];
  v_rows_f text[];
  v_rows_s text[];
  v_en_retard int;
  r record;
BEGIN
  -- KPIs
  SELECT count(*)::int INTO v_cmd_en_cours
    FROM purchase.commande WHERE statut IN ('envoyee', 'partiellement_recue');

  SELECT count(DISTINCT c.id)::int INTO v_receptions_attente
    FROM purchase.commande c
    JOIN purchase.ligne l ON l.commande_id = c.id
   WHERE c.statut IN ('envoyee', 'partiellement_recue')
     AND purchase._quantite_restante(l.id) > 0;

  SELECT count(*)::int INTO v_factures_impayees
    FROM purchase.facture_fournisseur WHERE statut IN ('recue', 'validee');

  SELECT coalesce(sum(montant_ttc), 0) INTO v_achats_mois
    FROM purchase.facture_fournisseur
   WHERE statut = 'payee'
     AND created_at >= date_trunc('month', now());

  SELECT coalesce(sum(montant_ttc), 0) INTO v_total_a_payer
    FROM purchase.facture_fournisseur WHERE statut IN ('recue', 'validee');

  SELECT count(*)::int INTO v_en_retard
    FROM purchase.commande
   WHERE statut IN ('envoyee', 'partiellement_recue')
     AND created_at < now() - interval '14 days';

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Commandes en cours', v_cmd_en_cours::text),
    pgv.stat('A réceptionner', v_receptions_attente::text),
    pgv.stat('Factures impayées', v_factures_impayees::text),
    pgv.stat('Achats du mois', to_char(v_achats_mois, 'FM999 990.00') || ' EUR'),
    pgv.stat('Total à payer', to_char(v_total_a_payer, 'FM999 990.00') || ' EUR'),
    CASE WHEN v_en_retard > 0
      THEN pgv.stat('En retard', v_en_retard::text || ' ' || pgv.badge('> 14j', 'danger'))
      ELSE pgv.stat('En retard', '0')
    END
  ]);

  -- Tab: Commandes récentes
  v_rows_c := ARRAY[]::text[];
  FOR r IN
    SELECT c.id, c.fournisseur_id, c.numero, cl.name AS fournisseur, c.objet, c.statut,
           purchase._total_ttc(c.id) AS ttc, c.created_at
      FROM purchase.commande c
      JOIN crm.client cl ON cl.id = c.fournisseur_id
     ORDER BY c.created_at DESC LIMIT 10
  LOOP
    v_rows_c := v_rows_c || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_commande', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
      format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur)),
      pgv.esc(r.objet),
      purchase._statut_badge(r.statut)
        || CASE WHEN r.statut IN ('envoyee', 'partiellement_recue')
                    AND r.created_at < now() - interval '14 days'
           THEN ' ' || pgv.badge('retard', 'danger')
           ELSE '' END,
      to_char(r.ttc, 'FM999 990.00') || ' EUR',
      to_char(r.created_at, 'DD/MM/YYYY')
    ];
  END LOOP;

  -- Tab: Factures récentes
  v_rows_f := ARRAY[]::text[];
  FOR r IN
    SELECT f.id, f.numero_fournisseur, c.numero AS cmd_numero,
           f.montant_ttc, f.statut, f.date_facture, f.date_echeance
      FROM purchase.facture_fournisseur f
      LEFT JOIN purchase.commande c ON c.id = f.commande_id
     ORDER BY f.created_at DESC LIMIT 10
  LOOP
    v_rows_f := v_rows_f || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero_fournisseur)),
      coalesce(r.cmd_numero, '—'),
      purchase._statut_badge(r.statut),
      to_char(r.montant_ttc, 'FM999 990.00') || ' EUR',
      to_char(r.date_facture, 'DD/MM/YYYY'),
      coalesce(to_char(r.date_echeance, 'DD/MM/YYYY'), '—')
    ];
  END LOOP;

  -- Tab: Top fournisseurs
  v_rows_s := ARRAY[]::text[];
  FOR r IN
    SELECT cl.id AS fournisseur_id, cl.name AS fournisseur,
           count(c.id)::int AS nb_cmd,
           coalesce(sum(purchase._total_ht(c.id)), 0) AS total_ht,
           max(c.created_at) AS last_cmd
      FROM purchase.commande c
      JOIN crm.client cl ON cl.id = c.fournisseur_id
     GROUP BY cl.id, cl.name
     ORDER BY total_ht DESC
     LIMIT 10
  LOOP
    v_rows_s := v_rows_s || ARRAY[
      format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur)),
      r.nb_cmd::text,
      to_char(r.total_ht, 'FM999 990.00') || ' EUR',
      to_char(r.last_cmd, 'DD/MM/YYYY')
    ];
  END LOOP;

  v_body := v_body || pgv.tabs(VARIADIC ARRAY[
    'Commandes récentes',
    CASE WHEN array_length(v_rows_c, 1) IS NULL
      THEN pgv.empty('Aucune commande', 'Créez votre première commande fournisseur.')
      ELSE pgv.md_table(ARRAY['Numéro', 'Fournisseur', 'Objet', 'Statut', 'Total TTC', 'Date'], v_rows_c)
    END,
    'Factures fournisseur',
    CASE WHEN array_length(v_rows_f, 1) IS NULL
      THEN pgv.empty('Aucune facture fournisseur')
      ELSE pgv.md_table(ARRAY['N° fournisseur', 'Commande', 'Statut', 'Montant TTC', 'Date facture', 'Echéance'], v_rows_f)
    END,
    'Top fournisseurs',
    CASE WHEN array_length(v_rows_s, 1) IS NULL
      THEN pgv.empty('Aucune commande')
      ELSE pgv.md_table(ARRAY['Fournisseur', 'Commandes', 'Total achats HT', 'Dernière commande'], v_rows_s)
    END
  ]);

  v_body := v_body || '<p>'
    || format('<a href="%s" role="button">Nouvelle commande</a>', pgv.call_ref('get_commande_form'))
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_index() IS 'Dashboard purchase: KPI stats + tabs commandes/factures récentes';

CREATE OR REPLACE FUNCTION purchase.get_recapitulatif(p_annee integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_annee int := coalesce(p_annee, extract(year FROM now())::int);
  v_body text;
  v_headers text[] := ARRAY['Fournisseur','Jan','Fév','Mar','Avr','Mai','Jun','Jul','Aoû','Sep','Oct','Nov','Déc','Total'];
  v_rows text[];
  r record;
  v_total_annuel numeric(12,2) := 0;
BEGIN
  v_body := '<h3>Récapitulatif achats ' || v_annee || '</h3>';

  -- Year navigation
  v_body := v_body || '<p>'
    || format('<a href="%s">&laquo; %s</a>',
       pgv.call_ref('get_recapitulatif', jsonb_build_object('p_annee', v_annee - 1)), v_annee - 1)
    || ' | <strong>' || v_annee || '</strong> | '
    || format('<a href="%s">%s &raquo;</a>',
       pgv.call_ref('get_recapitulatif', jsonb_build_object('p_annee', v_annee + 1)), v_annee + 1)
    || '</p>';

  -- Build rows per supplier
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT cl.id AS fournisseur_id, cl.name AS fournisseur,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 1) AS m01,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 2) AS m02,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 3) AS m03,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 4) AS m04,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 5) AS m05,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 6) AS m06,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 7) AS m07,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 8) AS m08,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 9) AS m09,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 10) AS m10,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 11) AS m11,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 12) AS m12
      FROM crm.client cl
     WHERE EXISTS (
       SELECT 1 FROM purchase.commande c3
        WHERE c3.fournisseur_id = cl.id
          AND extract(year FROM c3.created_at) = v_annee
     )
     ORDER BY cl.name
  LOOP
    DECLARE
      v_row_total numeric(12,2);
      v_months numeric[] := ARRAY[r.m01, r.m02, r.m03, r.m04, r.m05, r.m06,
                                   r.m07, r.m08, r.m09, r.m10, r.m11, r.m12];
    BEGIN
      v_row_total := r.m01 + r.m02 + r.m03 + r.m04 + r.m05 + r.m06
                   + r.m07 + r.m08 + r.m09 + r.m10 + r.m11 + r.m12;
      v_total_annuel := v_total_annuel + v_row_total;

      v_rows := v_rows || format('<a href="/crm/client?p_id=%s">%s</a>',
        r.fournisseur_id, pgv.esc(r.fournisseur));
      FOR i IN 1..12 LOOP
        v_rows := v_rows || CASE WHEN v_months[i] = 0 THEN '—'
          ELSE to_char(v_months[i], 'FM999 990') END;
      END LOOP;
      v_rows := v_rows || ('<strong>' || to_char(v_row_total, 'FM999 990') || '</strong>');
    END;
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun achat pour ' || v_annee);
  ELSE
    v_body := v_body || pgv.stat('Total annuel HT', to_char(v_total_annuel, 'FM999 990.00') || ' EUR');
    v_body := v_body || pgv.md_table(v_headers, v_rows);
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_recapitulatif(integer) IS 'Recapitulatif achats annuel — tableau croise fournisseur x mois avec totaux HT';

CREATE OR REPLACE FUNCTION purchase.nav_items()
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN '[{"href":"/","label":"Dashboard","icon":"home"},{"href":"/commande","label":"Commandes","icon":"shopping-cart"},{"href":"/facture_fournisseur","label":"Factures","icon":"receipt"},{"href":"/recapitulatif","label":"Récap.","icon":"bar-chart"},{"href":"/article_prix","label":"Prix articles","icon":"tag"}]'::jsonb;
END;
$function$;
COMMENT ON FUNCTION purchase.nav_items() IS 'Navigation items for purchase module';

CREATE OR REPLACE FUNCTION purchase.post_commande_annuler(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'p_id')::int;
  v_has_receptions bool;
BEGIN
  SELECT exists(SELECT 1 FROM purchase.reception WHERE commande_id = v_id) INTO v_has_receptions;

  IF v_has_receptions THEN
    RETURN '<template data-toast="error">Impossible d''annuler : des réceptions existent</template>';
  END IF;

  UPDATE purchase.commande SET statut = 'annulee'
   WHERE id = v_id AND statut IN ('brouillon', 'envoyee');

  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Commande introuvable ou non annulable</template>';
  END IF;

  RETURN format('<template data-toast="success">Commande annulée</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_commande', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_commande_annuler(jsonb) IS 'Cancel a purchase order (only if no receptions)';

CREATE OR REPLACE FUNCTION purchase.post_commande_envoyer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'p_id')::int;
BEGIN
  UPDATE purchase.commande SET statut = 'envoyee'
   WHERE id = v_id AND statut = 'brouillon';

  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Commande introuvable ou déjà envoyée</template>';
  END IF;

  RETURN format('<template data-toast="success">Commande envoyée</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_commande', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_commande_envoyer(jsonb) IS 'Mark purchase order as sent to supplier';

CREATE OR REPLACE FUNCTION purchase.post_commande_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'p_id')::int;
  v_fournisseur_id int := (p_data->>'p_fournisseur_id')::int;
  v_objet text := p_data->>'p_objet';
  v_notes text := coalesce(p_data->>'p_notes', '');
  v_date_livraison date := (p_data->>'p_date_livraison')::date;
  v_conditions text := coalesce(p_data->>'p_conditions_paiement', '');
BEGIN
  IF v_id IS NOT NULL THEN
    UPDATE purchase.commande
       SET fournisseur_id = v_fournisseur_id,
           objet = v_objet,
           notes = v_notes,
           date_livraison = v_date_livraison,
           conditions_paiement = v_conditions
     WHERE id = v_id AND statut = 'brouillon';

    IF NOT FOUND THEN
      RETURN '<template data-toast="error">Commande introuvable ou non modifiable</template>';
    END IF;

    RETURN format('<template data-toast="success">Commande mise à jour</template><template data-redirect="%s"></template>',
      pgv.call_ref('get_commande', jsonb_build_object('p_id', v_id)));
  ELSE
    INSERT INTO purchase.commande (numero, fournisseur_id, objet, notes, date_livraison, conditions_paiement)
    VALUES (purchase._next_numero('CMD'), v_fournisseur_id, v_objet, v_notes, v_date_livraison, v_conditions)
    RETURNING id INTO v_id;

    RETURN format('<template data-toast="success">Commande créée</template><template data-redirect="%s"></template>',
      pgv.call_ref('get_commande', jsonb_build_object('p_id', v_id)));
  END IF;
END;
$function$;
COMMENT ON FUNCTION purchase.post_commande_save(jsonb) IS 'Create or update a purchase order (draft only)';

CREATE OR REPLACE FUNCTION purchase.post_facture_comptabiliser(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'p_id')::int;
  v_facture record;
  v_tva numeric(12,2);
  v_entry_id int;
  v_ledger_exists boolean;
BEGIN
  -- Check facture exists and is payee
  SELECT * INTO v_facture FROM purchase.facture_fournisseur WHERE id = v_id;
  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Facture introuvable</template>';
  END IF;
  IF v_facture.statut <> 'payee' THEN
    RETURN '<template data-toast="error">La facture doit être payée avant comptabilisation</template>';
  END IF;
  IF v_facture.montant_ttc = 0 THEN
    RETURN '<template data-toast="error">Facture sans montant</template>';
  END IF;
  IF v_facture.comptabilisee THEN
    RETURN '<template data-toast="error">Facture déjà comptabilisée</template>';
  END IF;

  -- Check ledger schema exists
  SELECT EXISTS(SELECT 1 FROM pg_namespace WHERE nspname = 'ledger') INTO v_ledger_exists;
  IF NOT v_ledger_exists THEN
    RETURN '<template data-toast="error">Module ledger non déployé</template>';
  END IF;

  -- Compute TVA (TTC - HT)
  v_tva := v_facture.montant_ttc - v_facture.montant_ht;

  -- Create journal entry via dynamic SQL (no hard dependency on ledger)
  EXECUTE format(
    $e$INSERT INTO ledger.journal_entry (entry_date, reference, description)
    VALUES (%L, %L, %L) RETURNING id$e$,
    coalesce(v_facture.date_facture, CURRENT_DATE),
    'FAF-' || v_facture.numero_fournisseur,
    'Facture fournisseur ' || v_facture.numero_fournisseur
  ) INTO v_entry_id;

  -- 601 Achats matériaux — débit HT
  EXECUTE format(
    $e$INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
    VALUES (%s, (SELECT id FROM ledger.account WHERE code = '601'), %s, 0, %L)$e$,
    v_entry_id, v_facture.montant_ht,
    'Achat facture ' || v_facture.numero_fournisseur
  );

  -- 4456 TVA déductible — débit TVA
  IF v_tva > 0 THEN
    EXECUTE format(
      $e$INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
      VALUES (%s, (SELECT id FROM ledger.account WHERE code = '4456'), %s, 0, %L)$e$,
      v_entry_id, v_tva,
      'TVA déductible facture ' || v_facture.numero_fournisseur
    );
  END IF;

  -- 401 Fournisseurs — crédit TTC
  EXECUTE format(
    $e$INSERT INTO ledger.entry_line (journal_entry_id, account_id, debit, credit, label)
    VALUES (%s, (SELECT id FROM ledger.account WHERE code = '401'), 0, %s, %L)$e$,
    v_entry_id, v_facture.montant_ttc,
    'Fournisseur facture ' || v_facture.numero_fournisseur
  );

  -- Flag anti-doublon
  UPDATE purchase.facture_fournisseur SET comptabilisee = true WHERE id = v_id;

  RETURN '<template data-toast="success">Écriture comptable créée</template>'
    || format('<template data-redirect="%s"></template>',
       pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_facture_comptabiliser(jsonb) IS 'Comptabiliser une facture fournisseur payée: écriture 607/44566/401 dans ledger (EXECUTE dynamique, pas de hard dep)';

CREATE OR REPLACE FUNCTION purchase.post_facture_payer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'p_id')::int;
BEGIN
  UPDATE purchase.facture_fournisseur SET statut = 'payee'
   WHERE id = v_id AND statut = 'validee';

  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Facture introuvable ou non validée</template>';
  END IF;

  RETURN format('<template data-toast="success">Facture marquée payée</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_facture_payer(jsonb) IS 'Mark a supplier invoice as paid';

CREATE OR REPLACE FUNCTION purchase.post_facture_saisir(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
BEGIN
  INSERT INTO purchase.facture_fournisseur (
    commande_id, numero_fournisseur, montant_ht, montant_ttc,
    date_facture, date_echeance, notes
  ) VALUES (
    (p_data->>'p_commande_id')::int,
    p_data->>'p_numero_fournisseur',
    (p_data->>'p_montant_ht')::numeric,
    (p_data->>'p_montant_ttc')::numeric,
    (p_data->>'p_date_facture')::date,
    (p_data->>'p_date_echeance')::date,
    coalesce(p_data->>'p_notes', '')
  ) RETURNING id INTO v_id;

  RETURN format('<template data-toast="success">Facture fournisseur saisie</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_facture_saisir(jsonb) IS 'Record a supplier invoice';

CREATE OR REPLACE FUNCTION purchase.post_facture_valider(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'p_id')::int;
BEGIN
  UPDATE purchase.facture_fournisseur SET statut = 'validee'
   WHERE id = v_id AND statut = 'recue';

  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Facture introuvable ou déjà validée</template>';
  END IF;

  RETURN format('<template data-toast="success">Facture validée</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_facture_valider(jsonb) IS 'Validate a supplier invoice';

CREATE OR REPLACE FUNCTION purchase.post_ligne_ajouter(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_commande_id int := (p_data->>'p_commande_id')::int;
  v_statut text;
  v_sort int;
BEGIN
  SELECT statut INTO v_statut FROM purchase.commande WHERE id = v_commande_id;
  IF v_statut IS NULL OR v_statut <> 'brouillon' THEN
    RETURN '<template data-toast="error">Lignes modifiables uniquement sur brouillon</template>';
  END IF;

  SELECT coalesce(max(sort_order), 0) + 1 INTO v_sort
    FROM purchase.ligne WHERE commande_id = v_commande_id;

  -- Auto-fill price from catalog if article_id provided and no price given
  DECLARE
    v_article_id int := (p_data->>'p_article_id')::int;
    v_prix numeric := (p_data->>'p_prix_unitaire')::numeric;
  BEGIN
    IF v_article_id IS NOT NULL AND v_prix IS NULL
       AND EXISTS (SELECT 1 FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
                    WHERE n.nspname = 'catalog' AND c.relname = 'article') THEN
      EXECUTE format('SELECT prix_achat FROM catalog.article WHERE id = %L', v_article_id)
        INTO v_prix;
    END IF;

    INSERT INTO purchase.ligne (commande_id, sort_order, description, quantite, unite, prix_unitaire, tva_rate, article_id)
    VALUES (
      v_commande_id,
      v_sort,
      p_data->>'p_description',
      coalesce((p_data->>'p_quantite')::numeric, 1),
      coalesce(p_data->>'p_unite', 'u'),
      coalesce(v_prix, (p_data->>'p_prix_unitaire')::numeric),
      coalesce((p_data->>'p_tva_rate')::numeric, 20.00),
      v_article_id
    );
  END;

  RETURN format('<template data-toast="success">Ligne ajoutée</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_commande', jsonb_build_object('p_id', v_commande_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_ligne_ajouter(jsonb) IS 'Add a line to a draft purchase order';

CREATE OR REPLACE FUNCTION purchase.post_ligne_supprimer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_ligne_id int := (p_data->>'p_ligne_id')::int;
  v_commande_id int;
  v_statut text;
BEGIN
  SELECT l.commande_id, c.statut INTO v_commande_id, v_statut
    FROM purchase.ligne l
    JOIN purchase.commande c ON c.id = l.commande_id
   WHERE l.id = v_ligne_id;

  IF v_statut IS NULL OR v_statut <> 'brouillon' THEN
    RETURN '<template data-toast="error">Lignes modifiables uniquement sur brouillon</template>';
  END IF;

  DELETE FROM purchase.ligne WHERE id = v_ligne_id;

  RETURN format('<template data-toast="success">Ligne supprimée</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_commande', jsonb_build_object('p_id', v_commande_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_ligne_supprimer(jsonb) IS 'Remove a line from a draft purchase order';

CREATE OR REPLACE FUNCTION purchase.post_reception_creer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_commande_id int := (p_data->>'p_commande_id')::int;
  v_statut text;
  v_reception_id int;
  v_numero text;
  v_nb_lignes int := 0;
  v_all_received bool;
  r record;
BEGIN
  SELECT statut INTO v_statut FROM purchase.commande WHERE id = v_commande_id;
  IF v_statut NOT IN ('envoyee', 'partiellement_recue') THEN
    RETURN '<template data-toast="error">Commande non réceptionnable</template>';
  END IF;

  v_numero := purchase._next_numero('REC');
  INSERT INTO purchase.reception (commande_id, numero, notes)
  VALUES (v_commande_id, v_numero, coalesce(p_data->>'p_notes', ''))
  RETURNING id INTO v_reception_id;

  -- Réceptionner toutes les quantités restantes
  FOR r IN
    SELECT l.id AS ligne_id, purchase._quantite_restante(l.id) AS restante
      FROM purchase.ligne l
     WHERE l.commande_id = v_commande_id
       AND purchase._quantite_restante(l.id) > 0
  LOOP
    INSERT INTO purchase.reception_ligne (reception_id, ligne_id, quantite_recue)
    VALUES (v_reception_id, r.ligne_id, r.restante);
    v_nb_lignes := v_nb_lignes + 1;
  END LOOP;

  IF v_nb_lignes = 0 THEN
    -- Rien à réceptionner, rollback reception
    DELETE FROM purchase.reception WHERE id = v_reception_id;
    RETURN '<template data-toast="error">Tout est déjà réceptionné</template>';
  END IF;

  -- Vérifier si tout est reçu
  SELECT NOT exists(
    SELECT 1 FROM purchase.ligne l
     WHERE l.commande_id = v_commande_id
       AND purchase._quantite_restante(l.id) > 0
  ) INTO v_all_received;

  IF v_all_received THEN
    UPDATE purchase.commande SET statut = 'recue' WHERE id = v_commande_id;
  ELSE
    UPDATE purchase.commande SET statut = 'partiellement_recue' WHERE id = v_commande_id;
  END IF;

  -- TODO: créer mouvements stock quand module stock implémenté

  RETURN format('<template data-toast="success">Réception %s créée (%s lignes)</template><template data-redirect="%s"></template>',
    v_numero, v_nb_lignes,
    pgv.call_ref('get_commande', jsonb_build_object('p_id', v_commande_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_reception_creer(jsonb) IS 'Create a reception for all remaining quantities of a purchase order';

GRANT USAGE ON SCHEMA purchase TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA purchase TO web_anon;

-- Schema: purchase_ut
CREATE SCHEMA IF NOT EXISTS purchase_ut;

CREATE OR REPLACE FUNCTION purchase_ut.test_commande_annuler()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_result text;
  v_fournisseur_id int;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  INSERT INTO crm.client (type, name, tags)
  VALUES ('company', '_test_annuler_', ARRAY['fournisseur'])
  RETURNING id INTO v_fournisseur_id;

  -- Create + add line
  v_result := purchase.post_commande_save(jsonb_build_object(
    'p_fournisseur_id', v_fournisseur_id,
    'p_objet', 'Test annulation'
  ));
  SELECT id INTO v_id FROM purchase.commande WHERE objet = 'Test annulation';

  v_result := purchase.post_ligne_ajouter(jsonb_build_object(
    'p_commande_id', v_id,
    'p_description', 'Ligne test',
    'p_prix_unitaire', 10.00
  ));

  -- Cancel from brouillon
  v_result := purchase.post_commande_annuler(jsonb_build_object('p_id', v_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'cancel brouillon succeeds');
  RETURN NEXT is((SELECT statut FROM purchase.commande WHERE id = v_id), 'annulee', 'status is annulee');

  -- Cannot cancel again
  v_result := purchase.post_commande_annuler(jsonb_build_object('p_id', v_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="error"%', 'cannot cancel already cancelled');

  -- Test cancel from envoyee
  UPDATE purchase.commande SET statut = 'brouillon' WHERE id = v_id;
  v_result := purchase.post_commande_envoyer(jsonb_build_object('p_id', v_id));
  v_result := purchase.post_commande_annuler(jsonb_build_object('p_id', v_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'cancel envoyee succeeds');

  -- Test cannot cancel with receptions
  UPDATE purchase.commande SET statut = 'envoyee' WHERE id = v_id;
  INSERT INTO purchase.reception (commande_id, numero) VALUES (v_id, 'REC-TEST-ANN');
  v_result := purchase.post_commande_annuler(jsonb_build_object('p_id', v_id));
  RETURN NEXT ok(v_result LIKE '%des réceptions existent%', 'cannot cancel with receptions');

  -- Cleanup
  DELETE FROM purchase.reception WHERE commande_id = v_id;
  DELETE FROM purchase.ligne WHERE commande_id = v_id;
  DELETE FROM purchase.commande WHERE id = v_id;
  DELETE FROM crm.client WHERE id = v_fournisseur_id;
END;
$function$;
COMMENT ON FUNCTION purchase_ut.test_commande_annuler() IS 'Test cancel order transitions and guards';

CREATE OR REPLACE FUNCTION purchase_ut.test_commande_workflow()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_result text;
  v_fournisseur_id int;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  -- Setup: create a supplier
  INSERT INTO crm.client (type, name, tags)
  VALUES ('company', '_test_fournisseur_', ARRAY['fournisseur'])
  RETURNING id INTO v_fournisseur_id;

  -- Create order
  v_result := purchase.post_commande_save(jsonb_build_object(
    'p_fournisseur_id', v_fournisseur_id,
    'p_objet', 'Test commande workflow'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'create order returns success');

  SELECT id INTO v_id FROM purchase.commande WHERE objet = 'Test commande workflow';
  RETURN NEXT ok(v_id IS NOT NULL, 'order created');

  -- Add lines
  v_result := purchase.post_ligne_ajouter(jsonb_build_object(
    'p_commande_id', v_id,
    'p_description', 'Test article',
    'p_quantite', 5,
    'p_prix_unitaire', 10.00
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'add line returns success');

  -- Send
  v_result := purchase.post_commande_envoyer(jsonb_build_object('p_id', v_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'send returns success');
  RETURN NEXT is((SELECT statut FROM purchase.commande WHERE id = v_id), 'envoyee', 'status is envoyee');

  -- Cannot add line to non-brouillon
  v_result := purchase.post_ligne_ajouter(jsonb_build_object(
    'p_commande_id', v_id,
    'p_description', 'Should fail',
    'p_prix_unitaire', 1.00
  ));
  RETURN NEXT ok(v_result LIKE '%brouillon%', 'cannot add line to sent order');

  -- Receive
  v_result := purchase.post_reception_creer(jsonb_build_object('p_commande_id', v_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'reception returns success');
  RETURN NEXT is((SELECT statut FROM purchase.commande WHERE id = v_id), 'recue', 'status is recue after full reception');

  -- Cleanup
  DELETE FROM purchase.reception_ligne WHERE reception_id IN (SELECT id FROM purchase.reception WHERE commande_id = v_id);
  DELETE FROM purchase.reception WHERE commande_id = v_id;
  DELETE FROM purchase.ligne WHERE commande_id = v_id;
  DELETE FROM purchase.commande WHERE id = v_id;
  DELETE FROM crm.client WHERE id = v_fournisseur_id;
END;
$function$;
COMMENT ON FUNCTION purchase_ut.test_commande_workflow() IS 'Test full purchase order workflow: create, send, receive';

CREATE OR REPLACE FUNCTION purchase_ut.test_facture_comptabiliser()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd_id int;
  v_fac_id int;
  v_result text;
  v_entry_count int;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  -- Edge: facture introuvable
  v_result := purchase.post_facture_comptabiliser(jsonb_build_object('p_id', -1));
  RETURN NEXT ok(v_result LIKE '%introuvable%', 'facture introuvable');

  -- Setup: create commande + facture + pay it
  INSERT INTO purchase.commande (numero, fournisseur_id, objet, statut)
  VALUES ('CMD-TEST-CPT', (SELECT id FROM crm.client LIMIT 1), 'Test compta', 'envoyee')
  RETURNING id INTO v_cmd_id;

  INSERT INTO purchase.facture_fournisseur
    (commande_id, numero_fournisseur, montant_ht, montant_ttc, date_facture, statut)
  VALUES (v_cmd_id, 'FAF-CPT-001', 1000.00, 1200.00, CURRENT_DATE, 'payee')
  RETURNING id INTO v_fac_id;

  -- Edge: montant_ttc = 0
  UPDATE purchase.facture_fournisseur SET montant_ht = 0, montant_ttc = 0 WHERE id = v_fac_id;
  v_result := purchase.post_facture_comptabiliser(jsonb_build_object('p_id', v_fac_id));
  RETURN NEXT ok(v_result LIKE '%sans montant%', 'facture sans montant');
  UPDATE purchase.facture_fournisseur SET montant_ht = 1000.00, montant_ttc = 1200.00 WHERE id = v_fac_id;

  -- Cannot comptabiliser non-payee
  UPDATE purchase.facture_fournisseur SET statut = 'validee' WHERE id = v_fac_id;
  v_result := purchase.post_facture_comptabiliser(jsonb_build_object('p_id', v_fac_id));
  RETURN NEXT ok(v_result LIKE '%doit être payée%', 'cannot comptabilise non-payee');

  -- Restore payee
  UPDATE purchase.facture_fournisseur SET statut = 'payee' WHERE id = v_fac_id;

  -- Count entries before
  SELECT count(*) INTO v_entry_count FROM ledger.journal_entry;

  -- Comptabiliser
  v_result := purchase.post_facture_comptabiliser(jsonb_build_object('p_id', v_fac_id));
  RETURN NEXT ok(v_result LIKE '%success%', 'comptabilisation succeeds');

  -- Verify entry created
  RETURN NEXT ok(
    (SELECT count(*) FROM ledger.journal_entry) = v_entry_count + 1,
    'journal entry created'
  );

  -- Verify lines: 607 debit HT, 44566 debit TVA, 401 credit TTC
  RETURN NEXT ok(
    EXISTS(SELECT 1 FROM ledger.entry_line el
      JOIN ledger.account a ON a.id = el.account_id
     WHERE el.journal_entry_id = (SELECT max(id) FROM ledger.journal_entry)
       AND a.code = '601' AND el.debit = 1000.00),
    '601 debited 1000 HT'
  );

  RETURN NEXT ok(
    EXISTS(SELECT 1 FROM ledger.entry_line el
      JOIN ledger.account a ON a.id = el.account_id
     WHERE el.journal_entry_id = (SELECT max(id) FROM ledger.journal_entry)
       AND a.code = '4456' AND el.debit = 200.00),
    '4456 debited 200 TVA'
  );

  RETURN NEXT ok(
    EXISTS(SELECT 1 FROM ledger.entry_line el
      JOIN ledger.account a ON a.id = el.account_id
     WHERE el.journal_entry_id = (SELECT max(id) FROM ledger.journal_entry)
       AND a.code = '401' AND el.credit = 1200.00),
    '401 credited 1200 TTC'
  );

  -- Verify comptabilisee flag set
  RETURN NEXT ok(
    (SELECT comptabilisee FROM purchase.facture_fournisseur WHERE id = v_fac_id),
    'comptabilisee flag is true'
  );

  -- Cannot comptabilise twice
  v_result := purchase.post_facture_comptabiliser(jsonb_build_object('p_id', v_fac_id));
  RETURN NEXT ok(v_result LIKE '%déjà comptabilisée%', 'cannot comptabilise twice');

  -- Cleanup
  DELETE FROM ledger.entry_line WHERE journal_entry_id = (SELECT max(id) FROM ledger.journal_entry);
  DELETE FROM ledger.journal_entry WHERE id = (SELECT max(id) FROM ledger.journal_entry);
  DELETE FROM purchase.facture_fournisseur WHERE id = v_fac_id;
  DELETE FROM purchase.commande WHERE id = v_cmd_id;
END;
$function$;
COMMENT ON FUNCTION purchase_ut.test_facture_comptabiliser() IS 'Test comptabilisation facture fournisseur: validation statut, écriture 607/44566/401';

CREATE OR REPLACE FUNCTION purchase_ut.test_facture_workflow()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd_id int;
  v_fac_id int;
  v_result text;
  v_fournisseur_id int;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  INSERT INTO crm.client (type, name, tags)
  VALUES ('company', '_test_facture_', ARRAY['fournisseur'])
  RETURNING id INTO v_fournisseur_id;

  -- Create a received order
  INSERT INTO purchase.commande (numero, fournisseur_id, objet, statut)
  VALUES ('CMD-TEST-FAC', v_fournisseur_id, 'Test facture', 'recue')
  RETURNING id INTO v_cmd_id;

  INSERT INTO purchase.ligne (commande_id, sort_order, description, quantite, prix_unitaire, tva_rate)
  VALUES (v_cmd_id, 1, 'Article test', 2, 100.00, 20.00);

  -- Saisir facture
  v_result := purchase.post_facture_saisir(jsonb_build_object(
    'p_commande_id', v_cmd_id,
    'p_numero_fournisseur', 'FAC-TEST-001',
    'p_montant_ht', 200.00,
    'p_montant_ttc', 240.00,
    'p_date_facture', now()::date::text
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'saisir facture succeeds');

  SELECT id INTO v_fac_id FROM purchase.facture_fournisseur WHERE numero_fournisseur = 'FAC-TEST-001';
  RETURN NEXT ok(v_fac_id IS NOT NULL, 'facture created');
  RETURN NEXT is((SELECT statut FROM purchase.facture_fournisseur WHERE id = v_fac_id), 'recue', 'initial status is recue');

  -- Valider
  v_result := purchase.post_facture_valider(jsonb_build_object('p_id', v_fac_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'valider succeeds');
  RETURN NEXT is((SELECT statut FROM purchase.facture_fournisseur WHERE id = v_fac_id), 'validee', 'status is validee');

  -- Cannot validate again
  v_result := purchase.post_facture_valider(jsonb_build_object('p_id', v_fac_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="error"%', 'cannot validate twice');

  -- Payer
  v_result := purchase.post_facture_payer(jsonb_build_object('p_id', v_fac_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'payer succeeds');
  RETURN NEXT is((SELECT statut FROM purchase.facture_fournisseur WHERE id = v_fac_id), 'payee', 'status is payee');

  -- Cannot pay again
  v_result := purchase.post_facture_payer(jsonb_build_object('p_id', v_fac_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="error"%', 'cannot pay twice');

  -- Cleanup
  DELETE FROM purchase.facture_fournisseur WHERE id = v_fac_id;
  DELETE FROM purchase.ligne WHERE commande_id = v_cmd_id;
  DELETE FROM purchase.commande WHERE id = v_cmd_id;
  DELETE FROM crm.client WHERE id = v_fournisseur_id;
END;
$function$;
COMMENT ON FUNCTION purchase_ut.test_facture_workflow() IS 'Test supplier invoice lifecycle: saisir, valider, payer with guards';

CREATE OR REPLACE FUNCTION purchase_ut.test_ligne_supprimer()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_ligne_id int;
  v_result text;
  v_fournisseur_id int;
  v_count int;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  INSERT INTO crm.client (type, name, tags)
  VALUES ('company', '_test_suppr_', ARRAY['fournisseur'])
  RETURNING id INTO v_fournisseur_id;

  v_result := purchase.post_commande_save(jsonb_build_object(
    'p_fournisseur_id', v_fournisseur_id,
    'p_objet', 'Test suppression ligne'
  ));
  SELECT id INTO v_id FROM purchase.commande WHERE objet = 'Test suppression ligne';

  -- Add 2 lines
  v_result := purchase.post_ligne_ajouter(jsonb_build_object(
    'p_commande_id', v_id, 'p_description', 'Ligne A', 'p_prix_unitaire', 10.00));
  v_result := purchase.post_ligne_ajouter(jsonb_build_object(
    'p_commande_id', v_id, 'p_description', 'Ligne B', 'p_prix_unitaire', 20.00));

  SELECT count(*)::int INTO v_count FROM purchase.ligne WHERE commande_id = v_id;
  RETURN NEXT is(v_count, 2, '2 lines added');

  -- Delete one
  SELECT id INTO v_ligne_id FROM purchase.ligne WHERE commande_id = v_id ORDER BY sort_order LIMIT 1;
  v_result := purchase.post_ligne_supprimer(jsonb_build_object('p_ligne_id', v_ligne_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'delete line succeeds');

  SELECT count(*)::int INTO v_count FROM purchase.ligne WHERE commande_id = v_id;
  RETURN NEXT is(v_count, 1, '1 line remaining');

  -- Cannot delete on envoyee
  v_result := purchase.post_commande_envoyer(jsonb_build_object('p_id', v_id));
  SELECT id INTO v_ligne_id FROM purchase.ligne WHERE commande_id = v_id LIMIT 1;
  v_result := purchase.post_ligne_supprimer(jsonb_build_object('p_ligne_id', v_ligne_id));
  RETURN NEXT ok(v_result LIKE '%brouillon%', 'cannot delete line on sent order');

  -- Cleanup
  DELETE FROM purchase.ligne WHERE commande_id = v_id;
  DELETE FROM purchase.commande WHERE id = v_id;
  DELETE FROM crm.client WHERE id = v_fournisseur_id;
END;
$function$;
COMMENT ON FUNCTION purchase_ut.test_ligne_supprimer() IS 'Test line deletion and guards';

CREATE OR REPLACE FUNCTION purchase_ut.test_pages_render()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  RETURN NEXT ok(length(purchase.brand()) > 0, 'brand() returns text');
  RETURN NEXT ok(purchase.nav_items() IS NOT NULL, 'nav_items() returns jsonb');
  RETURN NEXT ok(length(purchase.get_index()) > 0, 'get_index() returns HTML');
  RETURN NEXT ok(length(purchase.get_commande()) > 0, 'get_commande() list returns HTML');
  RETURN NEXT ok(length(purchase.get_commande_form()) > 0, 'get_commande_form() returns HTML');
  RETURN NEXT ok(length(purchase.get_facture_fournisseur()) > 0, 'get_facture_fournisseur() list returns HTML');
  RETURN NEXT ok(length(purchase.get_index()) > 100, 'get_index() has stats + tabs');
  RETURN NEXT ok(purchase.get_index() LIKE '%Top fournisseurs%', 'get_index() has Top fournisseurs tab');

  -- get_bon_commande needs an existing commande
  PERFORM purchase_qa.clean();
  PERFORM purchase_qa.seed();
  DECLARE v_cid int;
  BEGIN
    SELECT id INTO v_cid FROM purchase.commande LIMIT 1;
    RETURN NEXT ok(length(purchase.get_bon_commande(v_cid)) > 0, 'get_bon_commande() returns HTML');
    RETURN NEXT ok(purchase.get_bon_commande(v_cid) LIKE '%pgv-print%', 'get_bon_commande() has print class');
  END;

  -- get_recapitulatif
  RETURN NEXT ok(length(purchase.get_recapitulatif()) > 0, 'get_recapitulatif() returns HTML');
  RETURN NEXT ok(purchase.get_recapitulatif() LIKE '%Récapitulatif achats%', 'get_recapitulatif() has title');

  -- get_article_prix (with non-existent article -> empty state)
  RETURN NEXT ok(length(purchase.get_article_prix(99999)) > 0, 'get_article_prix() returns HTML');
  RETURN NEXT ok(purchase.get_article_prix(99999) LIKE '%Aucun achat%', 'get_article_prix() empty state');

  PERFORM purchase_qa.clean();
END;
$function$;
COMMENT ON FUNCTION purchase_ut.test_pages_render() IS 'Test all pages render without error';

